  describe('state invariants (stateful PBT)', () => {
    it('always: workspaces have required identity fields', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ workspace: fc.string(), name: fc.string({ minLength: 1, maxLength: 50 }), owner: fc.string({ minLength: 1, maxLength: 50 }), description: fc.string() }) }),
              fc.record({ action: fc.constant('save'), input: fc.record({ workspace: fc.string(), snapshot: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('restore'), input: fc.record({ workspace: fc.string() }) }),
              fc.record({ action: fc.constant('setDefault'), input: fc.record({ workspace: fc.string() }) }),
              fc.record({ action: fc.constant('delete'), input: fc.record({ workspace: fc.string() }) }),
              fc.record({ action: fc.constant('duplicate'), input: fc.record({ workspace: fc.string(), newName: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('list'), input: fc.record({ owner: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ workspace: fc.string() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = workspaceHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(workspaceHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: snapshot lost after save', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ workspace: fc.string(), name: fc.string({ minLength: 1, maxLength: 50 }), owner: fc.string({ minLength: 1, maxLength: 50 }), description: fc.string() }) }),
              fc.record({ action: fc.constant('save'), input: fc.record({ workspace: fc.string(), snapshot: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('restore'), input: fc.record({ workspace: fc.string() }) }),
              fc.record({ action: fc.constant('setDefault'), input: fc.record({ workspace: fc.string() }) }),
              fc.record({ action: fc.constant('delete'), input: fc.record({ workspace: fc.string() }) }),
              fc.record({ action: fc.constant('duplicate'), input: fc.record({ workspace: fc.string(), newName: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('list'), input: fc.record({ owner: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ workspace: fc.string() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = workspaceHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(workspaceHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: snapshot lost after save
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

